import { useState, useEffect } from 'react';
import { toast } from 'react-toastify';
import { FaSearch } from 'react-icons/fa';
import SchemeCard from '../components/SchemeCard';
import Spinner from '../components/Spinner';
import schemeService from '../api/schemeService';

function Schemes() {
  const [schemes, setSchemes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [filteredSchemes, setFilteredSchemes] = useState([]);

  useEffect(() => {
    const fetchSchemes = async () => {
      try {
        const data = await schemeService.getSchemes();
        setSchemes(data);
        setFilteredSchemes(data);
      } catch (error) {
        toast.error('Error fetching government schemes');
      } finally {
        setLoading(false);
      }
    };

    fetchSchemes();
  }, []);

  useEffect(() => {
    if (searchQuery.trim() === '') {
      setFilteredSchemes(schemes);
    } else {
      const filtered = schemes.filter(
        (scheme) =>
          scheme.schemeName.toLowerCase().includes(searchQuery.toLowerCase()) ||
          scheme.eligibility.toLowerCase().includes(searchQuery.toLowerCase()) ||
          scheme.benefits.toLowerCase().includes(searchQuery.toLowerCase()) ||
          (scheme.department && scheme.department.toLowerCase().includes(searchQuery.toLowerCase()))
      );
      setFilteredSchemes(filtered);
    }
  }, [searchQuery, schemes]);

  const handleSearch = async (e) => {
    e.preventDefault();
    
    if (searchQuery.trim() === '') {
      return;
    }

    setLoading(true);
    try {
      const data = await schemeService.searchSchemes(searchQuery);
      setFilteredSchemes(data);
    } catch (error) {
      toast.error('Error searching schemes');
      setFilteredSchemes(schemes);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return <Spinner />;
  }

  return (
    <div>
      <h1 className="text-3xl font-bold text-blue-700 mb-6">
        Government Agricultural Schemes
      </h1>
      
      <div className="bg-white p-6 rounded-lg shadow-md mb-8">
        <h2 className="text-xl font-semibold text-gray-800 mb-4">
          Find Schemes & Subsidies
        </h2>
        <p className="text-gray-600 mb-4">
          Discover government schemes, subsidies, and benefits available for
          farmers. Search by scheme name, eligibility criteria, or benefits.
        </p>
        
        <form onSubmit={handleSearch} className="flex mb-2">
          <div className="relative flex-grow">
            <input
              type="text"
              className="w-full px-4 py-2 rounded-l-lg border border-gray-300 focus:outline-none focus:ring-2 focus:ring-blue-500"
              placeholder="Search for schemes..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
            />
            <button
              type="submit"
              className="absolute right-0 top-0 h-full px-3 bg-blue-500 text-white rounded-r-lg hover:bg-blue-600"
            >
              <FaSearch />
            </button>
          </div>
        </form>
      </div>

      {filteredSchemes.length === 0 ? (
        <div className="bg-white p-6 rounded-lg shadow-md text-center">
          <p className="text-gray-500">
            No schemes found matching your search criteria.
          </p>
        </div>
      ) : (
        <div className="space-y-6">
          {filteredSchemes.map((scheme) => (
            <SchemeCard key={scheme._id} scheme={scheme} />
          ))}
        </div>
      )}
    </div>
  );
}

export default Schemes;
